import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, SurveyData, PipeData } from './types';
import { LOGO_URL, STATUS_OPTIONS, FUNCTION_OPTIONS, TYPE_OPTIONS, SHAPES, MATERIALS, OPENING_TYPES, ATMOSPHERE_OPTIONS, SILT_DEBRIS_OPTIONS } from './constants';
import PipeTable from './components/PipeTable';
import PhotoUpload from './components/PhotoUpload';
import { searchLocationInfo, fastAssist } from './services/geminiService';

const App: React.FC = () => {
  const [data, setData] = useState<SurveyData>(INITIAL_DATA);
  const [loadingSearch, setLoadingSearch] = useState(false);
  const [assistantVisible, setAssistantVisible] = useState(false);
  const [assistantQuery, setAssistantQuery] = useState('');
  const [assistantResponse, setAssistantResponse] = useState('');
  const [locationUrls, setLocationUrls] = useState<string[]>([]);

  const handleChange = (field: keyof SurveyData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const handlePipeChangeByRef = (ref: string, field: keyof PipeData, value: string) => {
    const isOutgoing = ['X', 'Y'].includes(ref);
    const listKey = isOutgoing ? 'outgoingPipes' : 'incomingPipes';
    const newList = [...data[listKey]];
    const index = newList.findIndex(p => p.ref === ref);
    if (index !== -1) {
      newList[index] = { ...newList[index], [field]: value };
      setData(prev => ({ ...prev, [listKey]: newList }));
    }
  };

  const toggleArrayItem = (field: keyof SurveyData, item: string) => {
    const current = (data[field] as string[]);
    const updated = current.includes(item) 
      ? current.filter(i => i !== item)
      : [...current, item];
    handleChange(field, updated);
  };

  const handleLocationSearch = async () => {
      if (!data.location) return;
      setLoadingSearch(true);

      let lat, lng;
      try {
          const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
              navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
          });
          lat = pos.coords.latitude;
          lng = pos.coords.longitude;
      } catch (e) {
          console.warn("Geolocation failed or denied.");
      }

      const { text, urls } = await searchLocationInfo(data.location, lat, lng);
      setLocationUrls(urls);

      if (text) {
          const parts = text.split(',');
          const potentialTown = parts.length > 1 ? parts[parts.length - 2]?.trim() : '';
          setData(prev => ({
              ...prev,
              town: prev.town || potentialTown || '',
              remarks: (prev.remarks + '\nVerified Location: ' + text).trim()
          }));
      }
      setLoadingSearch(false);
  };

  const handleAssistantSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!assistantQuery) return;
      setAssistantResponse('Thinking...');
      const response = await fastAssist(assistantQuery);
      setAssistantResponse(response);
  }

  const handlePrint = () => {
    window.print();
  };

  const allPipes = [...data.incomingPipes, ...data.outgoingPipes];

  return (
    <div className="min-h-screen bg-slate-100 p-4 md:p-8 font-sans print:p-0 print:bg-white">
      {/* Top Bar (No Print) */}
      <div className="max-w-[210mm] mx-auto mb-6 flex justify-between items-center no-print">
        <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <span className="material-icons text-brand-600">room</span>
            Clever Works Smart Survey
        </h1>
        <div className="flex gap-2">
            <button 
                onClick={() => setAssistantVisible(!assistantVisible)}
                className="bg-brand-600 text-white px-4 py-2 rounded shadow-md hover:bg-brand-700 transition flex items-center gap-2"
            >
                🤖 Assistant
            </button>
            <button 
                onClick={handlePrint}
                className="bg-slate-800 text-white px-4 py-2 rounded shadow-md hover:bg-slate-900 transition flex items-center gap-2"
            >
                🖨️ Print Card
            </button>
        </div>
      </div>

      {/* AI Assistant Sidebar */}
      {assistantVisible && (
          <div className="fixed right-4 bottom-4 w-80 bg-white rounded-lg shadow-2xl border border-slate-200 z-50 overflow-hidden no-print">
              <div className="bg-brand-600 p-3 text-white font-bold flex justify-between items-center">
                  <span>Assistant (Flash-Lite)</span>
                  <button onClick={() => setAssistantVisible(false)} className="hover:bg-brand-700 rounded px-1">✕</button>
              </div>
              <div className="p-4 h-64 overflow-y-auto bg-slate-50 text-sm">
                  {assistantResponse ? (
                      <div className="whitespace-pre-wrap">{assistantResponse}</div>
                  ) : (
                      <p className="text-slate-400 italic">Ask me about drainage survey standards or help with data entry...</p>
                  )}
              </div>
              <form onSubmit={handleAssistantSubmit} className="p-2 border-t flex gap-2 bg-white">
                  <input 
                    className="flex-1 border rounded px-3 py-1.5 text-sm focus:ring-1 focus:ring-brand-500 outline-none"
                    value={assistantQuery}
                    onChange={e => setAssistantQuery(e.target.value)}
                    placeholder="Type your question..."
                  />
                  <button type="submit" className="bg-brand-600 text-white px-3 py-1.5 rounded text-sm font-medium">Ask</button>
              </form>
          </div>
      )}

      {/* Page 1: Header -> Combined Pipe Table */}
      <div className="page-segment">
        <div className="flex justify-between items-start mb-4 border-b-2 border-brand-900 pb-2">
            <div>
                <h1 className="text-xl font-bold text-slate-900 uppercase tracking-tight">Manhole Survey Card</h1>
                <p className="text-[9px] text-slate-500 font-mono">Digital ID: {data.mhNo || 'UNASSIGNED'}</p>
            </div>
            <div>
                <img src={LOGO_URL} alt="Clever Works Ltd" className="h-12 object-contain" />
            </div>
        </div>

        <div className="grid grid-cols-2 gap-x-6 gap-y-1.5 mb-4 text-xs">
            <div className="flex items-center">
                <label className="w-20 font-semibold text-slate-700">Card No</label>
                <input type="text" className="flex-1 border-b border-slate-300 focus:border-brand-500 outline-none px-1" value={data.cardNo} onChange={(e) => handleChange('cardNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-semibold text-slate-700">Map No</label>
                <input type="text" className="flex-1 border-b border-slate-300 focus:border-brand-500 outline-none px-1" value={data.mapNo} onChange={(e) => handleChange('mapNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-semibold text-slate-700">Catchment</label>
                <input type="text" className="flex-1 border-b border-slate-300 focus:border-brand-500 outline-none px-1" value={data.catchment} onChange={(e) => handleChange('catchment', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-semibold text-slate-700">MH No</label>
                <input type="text" className="flex-1 border-b border-slate-300 focus:border-brand-500 outline-none px-1 font-mono font-bold text-brand-700" value={data.mhNo} onChange={(e) => handleChange('mhNo', e.target.value)} />
            </div>
             <div className="col-span-2 flex items-center">
                <label className="w-20 font-semibold text-slate-700">Location</label>
                <div className="flex-1 flex relative">
                     <input 
                        type="text" 
                        className="w-full border-b border-slate-300 focus:border-brand-500 outline-none px-1 bg-brand-50/10" 
                        value={data.location} 
                        placeholder="Search address or street..."
                        onChange={(e) => handleChange('location', e.target.value)} 
                    />
                    <button 
                        onClick={handleLocationSearch}
                        disabled={loadingSearch}
                        className="absolute right-0 top-0 text-brand-500 hover:text-brand-700 no-print flex items-center gap-1 text-[10px]"
                    >
                        {loadingSearch ? '...' : '📍 Search'}
                    </button>
                </div>
            </div>
             <div className="col-span-2 flex items-center">
                <label className="w-20 font-semibold text-slate-700">Town</label>
                <input type="text" className="flex-1 border-b border-slate-300 focus:border-brand-500 outline-none px-1" value={data.town} onChange={(e) => handleChange('town', e.target.value)} />
            </div>
        </div>

        <div className="grid grid-cols-4 gap-2 border-y border-slate-300 py-1.5 mb-4 bg-slate-50 print:bg-transparent">
             <div className="flex flex-col border-r border-slate-200 px-2">
                <label className="text-[9px] uppercase font-bold text-slate-500">Status</label>
                <select className="bg-transparent border-none text-xs font-semibold p-0" value={data.status} onChange={(e) => handleChange('status', e.target.value)}>
                    <option value="">Select...</option>
                    {STATUS_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
