             <div className="flex flex-col border-r border-slate-200 px-2">
                <label className="text-[9px] uppercase font-bold text-slate-500">Function</label>
                 <select className="bg-transparent border-none text-xs font-semibold p-0" value={data.function} onChange={(e) => handleChange('function', e.target.value)}>
                    <option value="">Select...</option>
                    {FUNCTION_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
             </div>
             <div className="flex flex-col border-r border-slate-200 px-2">
                <label className="text-[9px] uppercase font-bold text-slate-500">MH Type</label>
                 <select className="bg-transparent border-none text-xs font-semibold p-0" value={data.mhType} onChange={(e) => handleChange('mhType', e.target.value)}>
                    <option value="">Select...</option>
                    {TYPE_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
             </div>
             <div className="flex flex-col px-2">
                <label className="text-[9px] uppercase font-bold text-slate-500">Date</label>
                <input type="date" className="bg-transparent text-xs font-semibold p-0" value={data.date} onChange={(e) => handleChange('date', e.target.value)} />
             </div>
        </div>

        <div className="mb-4">
            <h4 className="text-[10px] font-bold uppercase mb-1 text-brand-900 border-b border-brand-200 pb-0.5">Cover Details</h4>
            <div className="mb-1.5">
                <table className="w-full text-[9px] border-collapse border border-slate-400">
                    <thead>
                        <tr className="bg-slate-50">
                            <th className="border border-slate-400 p-1">Level (m)</th>
                            <th className="border border-slate-400 p-1">Duty</th>
                            <th className="border border-slate-400 p-1" colSpan={2}>Size (mm)</th>
                            <th className="border border-slate-400 p-1" colSpan={2}>Clear Op (mm)</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr>
                            <td className="border border-slate-400 p-0">
                                <input type="text" className="w-full p-1 text-center" value={data.coverLevel} onChange={e => handleChange('coverLevel', e.target.value)} />
                            </td>
                            <td className="border border-slate-400 p-0">
                                <select className="w-full p-1 bg-transparent text-center" value={data.coverDuty} onChange={e => handleChange('coverDuty', e.target.value)}>
                                    <option value=""></option>
                                    <option value="H">Heavy</option>
                                    <option value="M">Medium</option>
                                    <option value="L">Light</option>
                                </select>
                            </td>
                            <td className="border border-slate-400 p-0">
                                <input type="text" placeholder="L" className="w-full p-1 text-center" value={data.coverLength} onChange={e => handleChange('coverLength', e.target.value)} />
                            </td>
                            <td className="border border-slate-400 p-0">
                                <input type="text" placeholder="W" className="w-full p-1 text-center" value={data.coverWidth} onChange={e => handleChange('coverWidth', e.target.value)} />
                            </td>
                            <td className="border border-slate-400 p-0">
                                <input type="text" placeholder="L" className="w-full p-1 text-center" value={data.clearOpeningLength} onChange={e => handleChange('clearOpeningLength', e.target.value)} />
                            </td>
                            <td className="border border-slate-400 p-0">
                                <input type="text" placeholder="W" className="w-full p-1 text-center" value={data.clearOpeningWidth} onChange={e => handleChange('clearOpeningWidth', e.target.value)} />
