            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[8px] uppercase font-bold text-slate-500 block mb-0.5">Shape</label>
                    <div className="flex flex-wrap gap-x-2 gap-y-0.5 p-1 border border-slate-300 rounded bg-slate-50/20">
                        {SHAPES.map(shape => (
                            <label key={shape} className="flex items-center gap-1 text-[9px] cursor-pointer">
                                <input type="checkbox" className="scale-75 accent-brand-600" checked={data.coverShape.includes(shape)} onChange={() => toggleArrayItem('coverShape', shape)} />
                                {shape}
                            </label>
                        ))}
                    </div>
                </div>
                <div>
                    <label className="text-[8px] uppercase font-bold text-slate-500 block mb-0.5">Opening</label>
                    <div className="flex flex-wrap gap-x-2 gap-y-0.5 p-1 border border-slate-300 rounded bg-slate-50/20">
                        {OPENING_TYPES.map(type => (
                            <label key={type} className="flex items-center gap-1 text-[9px] cursor-pointer">
                                <input type="checkbox" className="scale-75 accent-brand-600" checked={data.openingType.includes(type)} onChange={() => toggleArrayItem('openingType', type)} />
