                    </div>
                </div>
            </div>
        </div>

        <PipeTable 
            title="Sewer Pipe Details (A-G Incoming, X-Y Outgoing)" 
            pipes={allPipes} 
            onChange={handlePipeChangeByRef} 
        />
      </div>

      {/* Page 2: Chamber Details -> Remarks */}
      <div className="page-segment">
        <div className="mb-6 border border-slate-400 rounded-sm overflow-hidden bg-white">
            <h3 className="text-[10px] font-bold uppercase p-1 bg-slate-50 text-brand-900 border-b border-slate-400 flex justify-between">
                <span>Chamber Details</span>
                <span className="text-[8px] text-slate-400 font-normal">Environmental & Structural Data</span>
