                    </div>
                    <div className="flex flex-col">
                        <label className="text-[8px] font-bold text-slate-500 uppercase">Shaft Depth (mm)</label>
                        <input type="text" className="w-full border-b border-slate-300 text-center" value={data.shaftDepth} onChange={e => handleChange('shaftDepth', e.target.value)} />
                    </div>
                    <div>
                        <label className="text-[8px] font-bold text-brand-900 uppercase block">Surcharge?</label>
                        <div className="flex gap-2">
