                            <label className="flex items-center gap-1 text-[9px] cursor-pointer"><input type="radio" className="scale-75 accent-brand-600" checked={!data.evidenceOfSurcharge} onChange={() => handleChange('evidenceOfSurcharge', false)} /> NO</label>
