                                {ATMOSPHERE_OPTIONS.map(opt => (
                                    <button key={opt} onClick={() => handleChange('atmosphere', opt)} className={`px-1 py-0.5 text-[8px] rounded border ${data.atmosphere === opt ? 'bg-brand-600 text-white' : 'bg-white'}`}>{opt}</button>
                                ))}
