                                    <button key={opt} onClick={() => handleChange('siltDebrisStatus', opt)} className={`px-1 py-0.5 text-[8px] rounded border ${data.siltDebrisStatus === opt ? 'bg-brand-600 text-white' : 'bg-white'}`}>{opt}</button>
                                ))}
                            </div>
