                    <div className="mt-1 pt-1 border-t border-slate-200">
                        <label className="text-[8px] uppercase font-bold text-slate-500 block">Construction</label>
                        <div className="flex flex-wrap gap-x-3 gap-y-0.5">
                            {MATERIALS.map(mat => (
                                <label key={mat} className="flex items-center gap-1 text-[9px] cursor-pointer"><input type="checkbox" className="scale-75 accent-brand-600" checked={data.constructionMaterial.includes(mat)} onChange={() => toggleArrayItem('constructionMaterial', mat)} /> {mat}</label>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div className="mb-6">
            <h3 className="text-[10px] font-bold uppercase mb-1 text-brand-900 border-b border-brand-200">Condition Information</h3>
            <table className="w-full text-[9px] text-center border-collapse">
