        <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <span className="w-3 h-3 bg-brand-600 rounded-sm"></span>
            Smart Survey Portal
        </h1>
        <div className="flex gap-2">
            <button 
                onClick={() => setAssistantVisible(!assistantVisible)}
                className="bg-brand-600 text-white px-4 py-2 rounded shadow-md hover:bg-brand-700 transition flex items-center gap-2 text-sm"
            >
                🤖 Assistant
            </button>
            <button 
                onClick={handlePrint}
                className="bg-slate-800 text-white px-4 py-2 rounded shadow-md hover:bg-slate-900 transition flex items-center gap-2 text-sm"
            >
                🖨️ PDF Export
            </button>
        </div>
      </div>

      {/* Assistant Modal (No Print) */}
      {assistantVisible && (
          <div className="fixed right-4 bottom-4 w-80 bg-white rounded-lg shadow-2xl border border-slate-200 z-50 overflow-hidden no-print">
              <div className="bg-brand-600 p-3 text-white font-bold flex justify-between items-center">
                  <span>Smart Assistant</span>
                  <button onClick={() => setAssistantVisible(false)} className="hover:bg-brand-700 rounded px-1">✕</button>
              </div>
              <div className="p-4 h-64 overflow-y-auto bg-slate-50 text-xs">
                  {assistantResponse ? (
                      <div className="whitespace-pre-wrap">{assistantResponse}</div>
                  ) : (
                      <p className="text-slate-400 italic">Ask me about STC25 codes or help with technical observations...</p>
                  )}
              </div>
              <form onSubmit={handleAssistantSubmit} className="p-2 border-t flex gap-2 bg-white">
                  <input 
                    className="flex-1 border rounded px-3 py-1.5 text-xs focus:ring-1 focus:ring-brand-500 outline-none"
                    value={assistantQuery}
                    onChange={e => setAssistantQuery(e.target.value)}
                    placeholder="Type a question..."
                  />
                  <button type="submit" className="bg-brand-600 text-white px-3 py-1.5 rounded text-xs font-medium">Ask</button>
              </form>
          </div>
      )}

