import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY || ''; // Ensure this is set in your environment
const ai = new GoogleGenAI({ apiKey });

export const analyzeManholePhoto = async (base64Image: string): Promise<string> => {
  try {
    const model = 'gemini-3-pro-preview';
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: "Analyze this manhole photo. Identify the material (brick, concrete, plastic), general condition (cracks, roots, blockage), and estimated silt level. Keep it brief for a survey report." }
        ]
      }
    });
    return response.text || "Analysis failed.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Error analyzing image.";
  }
};

export const editPhoto = async (base64Image: string, instruction: string): Promise<string | null> => {
  try {
    // Using flash image for editing as per instructions
    const model = 'gemini-2.5-flash-image';
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: instruction }
        ]
      }
    });

    // Check for image part in response
    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return part.inlineData.data;
        }
    }
    return null;
  } catch (error) {
    console.error("Gemini Edit Error:", error);
    return null;
  }
};

export const generatePlanSketch = async (description: string): Promise<string | null> => {
    try {
        const model = 'gemini-3-pro-image-preview';
        const response = await ai.models.generateContent({
            model,
            contents: {
                parts: [{ text: `Generate a technical engineering line drawing (plan view) of a manhole layout based on this description: ${description}. White background, black lines, technical style.` }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1",
                    imageSize: "1K" // Using 1K as it's sufficient for a report
                }
            }
        });

         for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return part.inlineData.data;
            }
        }
        return null;
    } catch (e) {
        console.error("Gemini Generate Error", e);
        return null;
    }
}

export const searchLocationInfo = async (query: string, lat?: number, lng?: number) => {
    try {
        // Maps grounding is only supported in Gemini 2.5 series models.
        const model = 'gemini-2.5-flash';
        const response = await ai.models.generateContent({
            model,
            contents: `Identify exact address and town details for this location query: "${query}". Include surrounding landmarks or road names if possible.`,
            config: {
                tools: [{ googleMaps: {} }],
                toolConfig: {
                    retrievalConfig: {
                        latLng: lat && lng ? { latitude: lat, longitude: lng } : undefined
                    }
                }
            }
        });

        const text = response.text;
        const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
        const urls = grounding?.map((chunk: any) => chunk.maps?.uri).filter(Boolean) || [];

        return { text, urls };
    } catch (e) {
        console.error("Maps Search Error", e);
        return { text: "Search unavailable", urls: [] };
    }
}

export const fastAssist = async (query: string): Promise<string> => {
    try {
        const model = 'gemini-2.5-flash-lite-latest'; // "Fast AI responses" feature
        const response = await ai.models.generateContent({
            model,
            contents: `You are a civil engineering assistant specialized in drainage. Answer briefly: ${query}`
        });
        return response.text || "";
    } catch (e) {
        return "";
    }
}

export const enhanceRemarks = async (text: string): Promise<string> => {
    try {
        const model = 'gemini-3-flash-preview';
        const response = await ai.models.generateContent({
            model,
            contents: `As a senior drainage engineer, professionalize and clarify the following site remarks for a formal STC25 survey report. Keep the technical facts but improve grammar and professional tone. Output only the improved text: "${text}"`
        });
        return response.text || text;
    } catch (e) {
        console.error("Enhance Error", e);
        return text;
    }
}

