import React, { useState, useRef } from 'react';
import { analyzeManholePhoto, editPhoto, generatePlanSketch } from '../services/geminiService';

interface PhotoUploadProps {
  label: string;
  value?: string;
  onChange: (base64: string) => void;
  enableGenAI?: boolean;
}

const PhotoUpload: React.FC<PhotoUploadProps> = ({ label, value, onChange, enableGenAI }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  const [isProcessing, setIsProcessing] = useState(false);
  const [editPrompt, setEditPrompt] = useState('');
  const [analysisResult, setAnalysisResult] = useState('');
  const [showTools, setShowTools] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onChange(reader.result as string);
        // Clear inputs so the same file can be re-selected if needed
        if (fileInputRef.current) fileInputRef.current.value = '';
        if (cameraInputRef.current) cameraInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!value) return;
    setIsProcessing(true);
    const base64Data = value.split(',')[1];
    const result = await analyzeManholePhoto(base64Data);
    setAnalysisResult(result);
    setIsProcessing(false);
  };

  const handleEdit = async () => {
    if (!value || !editPrompt) return;
    setIsProcessing(true);
    const base64Data = value.split(',')[1];
    const newImage = await editPhoto(base64Data, editPrompt);
    if (newImage) {
      onChange(`data:image/jpeg;base64,${newImage}`);
      setEditPrompt('');
    }
    setIsProcessing(false);
  };

  const handleGenerate = async () => {
    setIsProcessing(true);
    const newImage = await generatePlanSketch(`Standard manhole plan view with technical engineering style for label: ${label}`);
    if (newImage) {
      onChange(`data:image/png;base64,${newImage}`);
    }
    setIsProcessing(false);
  }

  return (
    <div className="border-2 border-dashed border-slate-300 rounded-lg p-2 flex flex-col items-center justify-center bg-slate-50 min-h-[220px] relative group transition-all hover:border-brand-400">
      {/* Hidden inputs for standard file picking and camera capture */}
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        className="hidden"
      />
      <input
        type="file"
        ref={cameraInputRef}
        onChange={handleFileChange}
        accept="image/*"
        capture="environment"
        className="hidden"
      />

      {value ? (
        <div className="relative w-full h-full flex flex-col items-center">
          <img src={value} alt={label} className="max-h-[180px] w-full object-contain rounded shadow-sm mb-2" />
          <div className="flex flex-wrap justify-center gap-1 no-print mt-1">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="px-2 py-1 bg-slate-200 text-slate-700 rounded text-[9px] font-bold hover:bg-slate-300"
              title="Upload from Storage"
            >
              📁 Storage
            </button>
            <button 
              onClick={() => cameraInputRef.current?.click()}
              className="px-2 py-1 bg-slate-200 text-slate-700 rounded text-[9px] font-bold hover:bg-slate-300"
              title="Take New Photo"
            >
              📸 Camera
            </button>
            <button 
              onClick={() => onChange('')}
              className="px-2 py-1 bg-red-100 text-red-700 rounded text-[9px] font-bold hover:bg-red-200"
            >
              Clear
            </button>
            {enableGenAI && (
               <button 
               onClick={() => setShowTools(!showTools)}
               className="px-2 py-1 bg-brand-100 text-brand-700 rounded text-[9px] font-bold hover:bg-brand-200 flex items-center gap-1"
             >
               AI
             </button>
            )}
          </div>

          {showTools && enableGenAI && (
             <div className="absolute top-full left-0 right-0 mt-1 p-2 bg-white border border-brand-200 rounded shadow-lg no-print z-50">
                <div className="flex flex-col gap-2">
                    <button 
                        onClick={handleAnalyze} 
                        disabled={isProcessing}
                        className="w-full text-left px-2 py-1 bg-slate-50 hover:bg-slate-100 rounded text-[10px] text-slate-700"
                    >
                        {isProcessing ? 'Analyzing...' : '🔍 Analyze'}
                    </button>
                    {analysisResult && (
                        <div className="text-[9px] p-1 bg-yellow-50 text-yellow-800 rounded border border-yellow-200">
                            {analysisResult}
                        </div>
                    )}
                    <div className="flex gap-1 border-t pt-1">
                        <input 
                            type="text" 
                            value={editPrompt}
                            onChange={(e) => setEditPrompt(e.target.value)}
                            placeholder="Edit prompt..."
                            className="flex-1 text-[10px] border rounded p-1"
                        />
                        <button 
                            onClick={handleEdit}
                            disabled={isProcessing || !editPrompt}
                            className="px-2 py-1 bg-brand-600 text-white rounded text-[10px]"
                        >
                            Go
                        </button>
                    </div>
                </div>
             </div>
          )}
        </div>
      ) : (
        <div className="text-center p-2 w-full">
            <p className="text-[10px] text-slate-500 mb-4 uppercase font-black tracking-wider border-b border-slate-200 pb-1">{label}</p>

            <div className="flex flex-col gap-3 w-full max-w-[150px] mx-auto no-print">
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 px-4 py-2.5 bg-white border border-slate-300 rounded-md shadow-sm text-[11px] font-bold text-slate-700 hover:bg-slate-50 hover:border-brand-400 transition-all"
                >
                    <span className="text-lg">📁</span> Storage
                </button>
                <button 
                    onClick={() => cameraInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 px-4 py-2.5 bg-brand-50 border border-brand-200 rounded-md shadow-sm text-[11px] font-bold text-brand-700 hover:bg-brand-100 transition-all"
                >
                    <span className="text-lg">📸</span> Camera
                </button>
            </div>

             {enableGenAI && label.toLowerCase().includes("plan") && (
                 <button 
                    onClick={handleGenerate}
                    className="mt-4 block mx-auto text-[9px] font-bold text-brand-600 hover:text-brand-800 no-print flex items-center gap-1"
                 >
                    ✨ AI Sketch Assistant
                 </button>
             )}
        </div>
      )}
    </div>
  );
};

