import React, { useState } from 'react';
import { INITIAL_DATA, SurveyData, PipeData } from './types';
import { LOGO_URL, STATUS_OPTIONS, FUNCTION_OPTIONS, TYPE_OPTIONS, SHAPES, MATERIALS, OPENING_TYPES, ATMOSPHERE_OPTIONS, SILT_DEBRIS_OPTIONS } from './constants';
import PipeTable from './components/PipeTable';
import PhotoUpload from './components/PhotoUpload';
import { searchLocationInfo, fastAssist, enhanceRemarks } from './services/geminiService';

const App: React.FC = () => {
  const [data, setData] = useState<SurveyData>(INITIAL_DATA);
  const [loadingSearch, setLoadingSearch] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [assistantVisible, setAssistantVisible] = useState(false);
  const [assistantQuery, setAssistantQuery] = useState('');
  const [assistantResponse, setAssistantResponse] = useState('');

  const handleChange = (field: keyof SurveyData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const handlePipeChangeByRef = (ref: string, field: keyof PipeData, value: string) => {
    const isOutgoing = ['X', 'Y'].includes(ref);
    const listKey = isOutgoing ? 'outgoingPipes' : 'incomingPipes';
    const newList = [...data[listKey]];
    const index = newList.findIndex(p => p.ref === ref);
    if (index !== -1) {
      newList[index] = { ...newList[index], [field]: value };
      setData(prev => ({ ...prev, [listKey]: newList }));
    }
  };

  const toggleArrayItem = (field: keyof SurveyData, item: string) => {
    const current = (data[field] as string[]);
    const updated = current.includes(item) 
      ? current.filter(i => i !== item)
      : [...current, item];
    handleChange(field, updated);
  };

  const handleLocationSearch = async () => {
      if (!data.location) return;
      setLoadingSearch(true);
      const { text } = await searchLocationInfo(data.location);
      if (text) {
          setData(prev => ({
              ...prev,
              remarks: (prev.remarks + '\nVerified Location: ' + text).trim()
          }));
      }
      setLoadingSearch(false);
  };

  const handleEnhanceRemarks = async () => {
      if (!data.remarks) return;
      setEnhancing(true);
      const enhanced = await enhanceRemarks(data.remarks);
      handleChange('remarks', enhanced);
      setEnhancing(false);
  };

  const handleAssistantSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!assistantQuery) return;
      setAssistantResponse('Thinking...');
      const response = await fastAssist(assistantQuery);
      setAssistantResponse(response);
  };

  const handlePrint = () => {
    window.print();
  };

  const getConditionColorClass = (val: string) => {
    if (val === 'Needs Attention') return 'bg-yellow-100 print:bg-yellow-100';
    if (val === 'Urgent') return 'bg-orange-200 print:bg-orange-200';
    return '';
  };

  const allPipes = [...data.incomingPipes, ...data.outgoingPipes];

  return (
    <div className="min-h-screen bg-slate-100 p-4 md:p-8 font-sans print:p-0 print:bg-white">
      {/* Controls Bar (No Print) */}
      <div className="max-w-[210mm] mx-auto mb-6 flex justify-between items-center no-print">
        <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <span className="w-3 h-3 bg-brand-600 rounded-sm"></span>
            Smart Survey Portal
        </h1>
        <div className="flex gap-2">
            <button 
                onClick={() => setAssistantVisible(!assistantVisible)}
                className="bg-brand-600 text-white px-4 py-2 rounded shadow-md hover:bg-brand-700 transition flex items-center gap-2 text-sm"
            >
                🤖 Assistant
            </button>
            <button 
                onClick={handlePrint}
                className="bg-slate-800 text-white px-4 py-2 rounded shadow-md hover:bg-slate-900 transition flex items-center gap-2 text-sm"
            >
                🖨️ PDF Export
            </button>
        </div>
      </div>

      {/* Assistant Modal (No Print) */}
      {assistantVisible && (
          <div className="fixed right-4 bottom-4 w-80 bg-white rounded-lg shadow-2xl border border-slate-200 z-50 overflow-hidden no-print">
              <div className="bg-brand-600 p-3 text-white font-bold flex justify-between items-center">
                  <span>Smart Assistant</span>
                  <button onClick={() => setAssistantVisible(false)} className="hover:bg-brand-700 rounded px-1">✕</button>
              </div>
              <div className="p-4 h-64 overflow-y-auto bg-slate-50 text-xs">
                  {assistantResponse ? (
                      <div className="whitespace-pre-wrap">{assistantResponse}</div>
                  ) : (
                      <p className="text-slate-400 italic">Ask me about STC25 codes or help with technical observations...</p>
                  )}
              </div>
              <form onSubmit={handleAssistantSubmit} className="p-2 border-t flex gap-2 bg-white">
                  <input 
                    className="flex-1 border rounded px-3 py-1.5 text-xs focus:ring-1 focus:ring-brand-500 outline-none"
                    value={assistantQuery}
                    onChange={e => setAssistantQuery(e.target.value)}
                    placeholder="Type a question..."
                  />
                  <button type="submit" className="bg-brand-600 text-white px-3 py-1.5 rounded text-xs font-medium">Ask</button>
              </form>
          </div>
      )}

      {/* PAGE 1: FULL DATA SHEET */}
      <div className="page-segment">
        {/* Massive 400% Enlarged Faded Watermark */}
        <img src={LOGO_URL} alt="" className="watermark" />

        {/* Header Section - Logo 10% larger (h-10) */}
        <div className="flex justify-between items-start mb-4 border-b border-brand-900 pb-1 relative z-10">
            <div>
                <h1 className="text-lg font-bold text-slate-900 uppercase tracking-tight">Manhole Survey Card</h1>
                <p className="text-[9px] text-slate-500 font-mono">STC25 COMPLIANT REF: {data.mhNo || 'PENDING'}</p>
            </div>
            <div>
                <img src={LOGO_URL} alt="Clever Works" className="h-10 object-contain" />
            </div>
        </div>

        {/* Top Metadata Grid */}
        <div className="grid grid-cols-2 gap-x-4 gap-y-1.5 mb-3 text-[10px] relative z-10">
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Card No</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.cardNo} onChange={(e) => handleChange('cardNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Map No</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.mapNo} onChange={(e) => handleChange('mapNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Catchment</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.catchment} onChange={(e) => handleChange('catchment', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-brand-700">Manhole ID</label>
                <input type="text" className="flex-1 border-b border-brand-500 px-1 font-mono font-bold" value={data.mhNo} onChange={(e) => handleChange('mhNo', e.target.value)} />
            </div>
            <div className="col-span-2 flex items-center">
                <label className="w-20 font-bold text-slate-600">Location</label>
                <div className="flex-1 flex relative">
                     <input type="text" className="w-full border-b border-slate-300 px-1" value={data.location} onChange={(e) => handleChange('location', e.target.value)} />
                    <button onClick={handleLocationSearch} className="absolute right-0 top-0 text-brand-600 no-print text-[9px] hover:underline">GPS Verify</button>
                </div>
            </div>
        </div>

        {/* Categorical Data Strip */}
        <div className="grid grid-cols-4 gap-2 border-y border-slate-300 py-2 mb-3 bg-slate-50/30 relative z-10">
             {['status', 'function', 'mhType', 'date'].map((field) => (
                <div key={field} className="flex flex-col px-2 border-r last:border-0 border-slate-200">
                    <label className="text-[8px] uppercase font-bold text-slate-400">{field === 'mhType' ? 'MH Type' : field}</label>
                    {field === 'date' ? (
                        <input type="date" className="bg-transparent text-[10px] font-bold p-0" value={data[field as keyof SurveyData] as string} onChange={(e) => handleChange(field as keyof SurveyData, e.target.value)} />
                    ) : (
                        <select className="bg-transparent border-none text-[10px] font-bold p-0" value={data[field as keyof SurveyData] as string} onChange={(e) => handleChange(field as keyof SurveyData, e.target.value)}>
                            <option value="">Select...</option>
                            {(field === 'status' ? STATUS_OPTIONS : field === 'function' ? FUNCTION_OPTIONS : TYPE_OPTIONS).map(o => (
                                <option key={o.value} value={o.value}>{o.label}</option>
                            ))}
                        </select>
                    )}
                </div>
             ))}
        </div>

        {/* Cover Details Table */}
        <div className="mb-3 relative z-10">
            <h4 className="text-[9px] font-bold uppercase mb-1 text-brand-900 border-b border-brand-200">Cover Details</h4>
            <table className="w-full text-[8.5px] border-collapse border border-slate-400 mb-2">
                <thead className="bg-slate-50">
                    <tr>
                        <th className="border border-slate-400 p-1">Level (m)</th>
                        <th className="border border-slate-400 p-1">Duty</th>
                        <th className="border border-slate-400 p-1" colSpan={2}>Size (mm)</th>
                        <th className="border border-slate-400 p-1" colSpan={2}>Clear Opening (mm)</th>
                    </tr>
                </thead>
                <tbody>
                    <tr className="h-6">
                        <td className="border border-slate-400 p-0"><input type="text" className="w-full text-center" value={data.coverLevel} onChange={e => handleChange('coverLevel', e.target.value)} /></td>
                        <td className="border border-slate-400 p-0">
                            <select className="w-full text-center bg-transparent" value={data.coverDuty} onChange={e => handleChange('coverDuty', e.target.value)}>
                                <option value=""></option>
                                <option value="H">H (Heavy)</option>
                                <option value="M">M (Medium)</option>
                                <option value="L">L (Light)</option>
                            </select>
                        </td>
                        <td className="border border-slate-400 p-0"><input type="text" placeholder="L" className="w-full text-center" value={data.coverLength} onChange={e => handleChange('coverLength', e.target.value)} /></td>
                        <td className="border border-slate-400 p-0"><input type="text" placeholder="W" className="w-full text-center" value={data.coverWidth} onChange={e => handleChange('coverWidth', e.target.value)} /></td>
                        <td className="border border-slate-400 p-0"><input type="text" placeholder="L" className="w-full text-center" value={data.clearOpeningLength} onChange={e => handleChange('clearOpeningLength', e.target.value)} /></td>
                        <td className="border border-slate-400 p-0"><input type="text" placeholder="W" className="w-full text-center" value={data.clearOpeningWidth} onChange={e => handleChange('clearOpeningWidth', e.target.value)} /></td>
                    </tr>
                </tbody>
            </table>

            {/* Geometric Configuration & Technical Features */}
            <div className="grid grid-cols-2 gap-2 text-[8px] font-bold uppercase tracking-tight">
                <div>
                    <span className="text-slate-500 mb-1 block">Geometric Configuration</span>
                    <div className="border border-slate-200 bg-brand-50/20 p-1.5 grid grid-cols-3 gap-y-1">
                        {SHAPES.map(shape => (
                            <label key={shape} className="flex items-center gap-1 cursor-pointer">
                                <input 
                                    type="checkbox" 
                                    className="w-2.5 h-2.5" 
                                    checked={data.coverShape.includes(shape)} 
                                    onChange={() => toggleArrayItem('coverShape', shape)} 
                                />
                                {shape.toUpperCase()}
                            </label>
                        ))}
                    </div>
                </div>
                <div>
                    <span className="text-slate-500 mb-1 block">Technical Features</span>
                    <div className="border border-slate-200 bg-brand-50/20 p-1.5 grid grid-cols-3 gap-y-1">
                        {OPENING_TYPES.map(type => (
                            <label key={type} className="flex items-center gap-1 cursor-pointer">
                                <input 
                                    type="checkbox" 
                                    className="w-2.5 h-2.5" 
                                    checked={data.openingType.includes(type)} 
                                    onChange={() => toggleArrayItem('openingType', type)} 
                                />
                                {type.toUpperCase()}
                            </label>
                        ))}
                    </div>
                </div>
            </div>
        </div>

        {/* Unified Pipe Table */}
        <div className="relative z-10">
            <PipeTable 
                title="Sewer Pipe Details (A-G Incoming | X-Y Outgoing)" 
                pipes={allPipes} 
                onChange={handlePipeChangeByRef} 
            />
        </div>

        {/* Chamber Details & Construction */}
        <div className="mb-3 border border-slate-300 rounded-sm bg-white relative z-10">
            <h3 className="text-[9px] font-bold uppercase p-1 bg-slate-50 border-b border-slate-300 text-brand-950">Chamber & Construction</h3>
            <div className="grid grid-cols-12 text-[8.5px]">
                <div className="col-span-4 border-r border-slate-200 p-2 space-y-2">
                    <div className="flex justify-between border-b border-slate-100">
                        <span className="font-bold text-slate-500">CHAMBER SIZE (MM)</span>
                        <input type="text" className="w-16 text-right font-bold" value={data.chamberSize} onChange={e => handleChange('chamberSize', e.target.value)} />
                    </div>
                    <div className="flex justify-between border-b border-slate-100">
                        <span className="font-bold text-slate-500">TOTAL DEPTH (MM)</span>
                        <input type="text" className="w-16 text-right font-bold" value={data.shaftDepth} onChange={e => handleChange('shaftDepth', e.target.value)} />
                    </div>
                    <div>
                        <span className="font-bold text-slate-500 block mb-1">SURCHARGE?</span>
                        <div className="flex gap-4">
                            <label className="flex items-center gap-1 cursor-pointer"><input type="radio" checked={data.evidenceOfSurcharge} onChange={() => handleChange('evidenceOfSurcharge', true)} /> YES</label>
                            <label className="flex items-center gap-1 cursor-pointer"><input type="radio" checked={!data.evidenceOfSurcharge} onChange={() => handleChange('evidenceOfSurcharge', false)} /> NO</label>
                        </div>
                    </div>
                </div>
                <div className="col-span-8 p-2">
                    <div className="grid grid-cols-2 gap-2 mb-2">
                        <div>
                            <span className="font-bold text-slate-500 uppercase text-[7px] block mb-1">Atmosphere</span>
                            <div className="flex flex-wrap gap-1">
                                {ATMOSPHERE_OPTIONS.map(opt => (
                                    <button key={opt} onClick={() => handleChange('atmosphere', opt)} className={`px-1.5 py-0.5 text-[8px] border rounded ${data.atmosphere === opt ? 'bg-brand-600 text-white border-brand-700' : 'bg-white border-slate-200'}`}>{opt}</button>
                                ))}
                            </div>
                        </div>
                        <div>
                            <span className="font-bold text-slate-500 uppercase text-[7px] block mb-1">Silt Status</span>
                            <div className="flex flex-wrap gap-1">
                                {SILT_DEBRIS_OPTIONS.map(opt => (
                                    <button key={opt} onClick={() => handleChange('siltDebrisStatus', opt)} className={`px-1.5 py-0.5 text-[8px] border rounded ${data.siltDebrisStatus === opt ? 'bg-brand-600 text-white border-brand-700' : 'bg-white border-slate-200'}`}>{opt}</button>
                                ))}
                            </div>
                        </div>
                    </div>
                    <div className="pt-1 border-t border-slate-100">
                        <span className="font-bold text-slate-500 uppercase text-[7px] block mb-1">Materials</span>
                        <div className="flex flex-wrap gap-x-3 gap-y-0.5">
                            {MATERIALS.map(mat => (
                                <label key={mat} className="flex items-center gap-1 cursor-pointer"><input type="checkbox" checked={data.constructionMaterial.includes(mat)} onChange={() => toggleArrayItem('constructionMaterial', mat)} /> {mat}</label>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Condition Assessment Grid with Dynamic Coloring */}
        <div className="mb-3 relative z-10">
            <h3 className="text-[9px] font-bold uppercase mb-1 text-brand-900 border-b border-brand-200">Condition Assessment</h3>
            <table className="w-full text-[8.5px] text-center border-collapse">
                <thead>
                    <tr className="bg-slate-50">
                        <th className="text-left p-1 border border-slate-300">Feature</th>
                        <th className="p-1 border border-slate-300">OK</th>
                        <th className="p-1 border border-slate-300">Attention</th>
                        <th className="p-1 border border-slate-300">Urgent</th>
                        <th className="text-left p-1 border border-slate-300">Feature</th>
                        <th className="p-1 border border-slate-300">OK</th>
                        <th className="p-1 border border-slate-300">Attention</th>
                        <th className="p-1 border border-slate-300">Urgent</th>
                    </tr>
                </thead>
                <tbody>
                    {[
                        ['conditionCover', 'Cover & Frame', 'conditionChamber', 'Chamber Walls'],
                        ['conditionShaft', 'Shaft / Corbel', 'conditionBenching', 'Benching'],
                        ['conditionIrons', 'Irons / Ladder', 'conditionChannel', 'Channel / Pipes']
                    ].map((row, idx) => {
                        const statusL = data[row[0] as keyof SurveyData] as string;
                        const statusR = data[row[2] as keyof SurveyData] as string;
                        const bgColorL = getConditionColorClass(statusL);
                        const bgColorR = getConditionColorClass(statusR);

                        return (
                            <tr key={idx} className="h-6">
                                <td className={`text-left p-1 font-bold border border-slate-300 transition-colors duration-300 ${bgColorL || 'bg-slate-50/20'}`}>{row[1]}</td>
                                {['OK', 'Needs Attention', 'Urgent'].map(s => (
                                    <td key={s} className={`border border-slate-300 transition-colors duration-300 ${bgColorL}`}>
                                        <input type="checkbox" className="scale-75 cursor-pointer" checked={statusL === s} onChange={() => handleChange(row[0] as keyof SurveyData, s)} />
                                    </td>
                                ))}
                                <td className={`text-left p-1 font-bold border border-slate-300 transition-colors duration-300 ${bgColorR || 'bg-slate-50/20'}`}>{row[3]}</td>
                                {['OK', 'Needs Attention', 'Urgent'].map(s => (
                                    <td key={s} className={`border border-slate-300 transition-colors duration-300 ${bgColorR}`}>
                                        <input type="checkbox" className="scale-75 cursor-pointer" checked={statusR === s} onChange={() => handleChange(row[2] as keyof SurveyData, s)} />
                                    </td>
                                ))}
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>

        {/* Remarks Section */}
        <div className="mb-2 relative z-10">
            <h3 className="text-[9px] font-bold uppercase text-brand-900 mb-1">General Remarks</h3>
            <textarea 
                className="w-full border border-slate-200 p-2 text-[9px] h-16 leading-snug rounded-sm bg-slate-50/10 mb-1" 
                value={data.remarks} 
                onChange={e => handleChange('remarks', e.target.value)} 
            />
            {/* AI Text Enhancer placed clearly UNDER the remarks area as requested */}
            <div className="flex justify-end">
                <button 
                    onClick={handleEnhanceRemarks}
                    disabled={enhancing || !data.remarks}
                    className="no-print bg-brand-600 hover:bg-brand-700 text-white text-[9px] font-bold py-1.5 px-4 rounded shadow-sm flex items-center gap-2 disabled:opacity-50 transition-all"
                >
                    {enhancing ? '✨ Professionalizing...' : '✨ AI Text Enhancer'}
                </button>
            </div>
        </div>
      </div>

      {/* PAGE 2: MEDIA & SKETCHES ONLY */}
      <div className="page-segment">
        {/* Massive 400% Enlarged Faded Watermark */}
        <img src={LOGO_URL} alt="" className="watermark" />

        {/* Header Section consistency - 10% bigger logo */}
        <div className="flex justify-between items-start mb-6 border-b border-brand-900 pb-1 relative z-10">
            <div>
                <h1 className="text-lg font-bold text-slate-900 uppercase tracking-tight">Site Photo Gallery</h1>
                <p className="text-[9px] text-slate-500 font-mono">STC25 COMPLIANT REF: {data.mhNo || 'PENDING'}</p>
            </div>
            <div>
                <img src={LOGO_URL} alt="Clever Works" className="h-10 object-contain" />
            </div>
        </div>

        <h3 className="text-[11px] font-bold uppercase mb-6 text-brand-900 border-b-4 border-brand-900 pb-2 relative z-10">Technical Sketch & Site Photos</h3>
        <div className="grid grid-cols-2 gap-8 relative z-10">
            <div className="flex flex-col gap-2">
                <PhotoUpload label="Manhole Plan (Technical Sketch)" value={data.photo1Url} onChange={(val) => handleChange('photo1Url', val)} enableGenAI />
                <p className="text-[9px] text-slate-400 text-center italic">Primary Engineering Plan</p>
            </div>
            <div className="flex flex-col gap-2">
                <PhotoUpload label="Site Location / Orientation" value={data.photo2Url} onChange={(val) => handleChange('photo2Url', val)} />
                <p className="text-[9px] text-slate-400 text-center italic">Surrounding Context</p>
            </div>
            <div className="flex flex-col gap-2">
                <PhotoUpload label="Internal Chamber View" value={data.photo3Url} onChange={(val) => handleChange('photo3Url', val)} enableGenAI />
                <p className="text-[9px] text-slate-400 text-center italic">Condition Evidence</p>
            </div>
            <div className="flex flex-col gap-2">
                <PhotoUpload label="Additional Detail / Damage" value={data.photo4Url} onChange={(val) => handleChange('photo4Url', val)} />
                <p className="text-[9px] text-slate-400 text-center italic">Supporting Evidence</p>
            </div>
        </div>

        <div className="mt-16 pt-12 text-center text-slate-200 text-[10px] uppercase tracking-[0.3em] font-black border-t border-slate-100 relative z-10">
            End of Record &bull; Clever Works Digital &bull; Card STC25
        </div>
      </div>
    </div>
  );
};

export default App;

export interface PipeData {
  id: string;
  ref: string; // A, B, C... or X, Y
  status?: string;
  flow?: string;
  invertLevel?: string;
  depth?: string;
  nodeRef?: string; // Upstream or Downstream Node Ref
  shape?: string;
  material?: string;
  diameter?: string;
  backdropDia?: string;
  backdropDepth?: string;
}

export interface SurveyData {
  // Header
  cardNo: string;
  mapNo: string;
  catchment: string;
  mhNo: string;
  location: string;
  town: string;

  // Meta
  status: string; 
  function: string; 
  mhType: string; 
  date: string;
  surveyor: string;

  // Cover
  coverShape: string[]; 
  coverLevel: string;
  coverDuty: string; 
  coverLength: string;
  coverWidth: string;
  openingType: string[]; 
  clearOpeningLength: string;
  clearOpeningWidth: string;

  // Pipes
  incomingPipes: PipeData[];
  outgoingPipes: PipeData[];

  // Construction
  chamberSize: string; 
  shaftSize: string;
  shaftDepth: string;
  constructionMaterial: string[]; 
  ladderStepRows: string;
  atmosphere: string; 
  siltDebrisStatus: string; 

  // Condition
  evidenceOfSurcharge: boolean;
  toxicAtmosphere: boolean;
  conditionCover: 'OK' | 'Needs Attention' | 'Urgent' | '';
  conditionShaft: 'OK' | 'Needs Attention' | 'Urgent' | '';
  conditionIrons: 'OK' | 'Needs Attention' | 'Urgent' | '';
  conditionChamber: 'OK' | 'Needs Attention' | 'Urgent' | '';
  conditionBenching: 'OK' | 'Needs Attention' | 'Urgent' | '';
  conditionChannel: 'OK' | 'Needs Attention' | 'Urgent' | '';

  depthFlow: string;
  depthSilt: string;
  surchargeHeight: string;

  remarks: string;

  // Media (4 Photos)
  photo1Url?: string; // Manhole Plan
  photo2Url?: string; // Manhole Location
  photo3Url?: string; // Internal View
  photo4Url?: string; // Additional Evidence
}

export const INITIAL_PIPES: PipeData[] = [
  { id: 'A', ref: 'A' }, { id: 'B', ref: 'B' }, { id: 'C', ref: 'C' },
  { id: 'D', ref: 'D' }, { id: 'E', ref: 'E' }, { id: 'F', ref: 'F' },
  { id: 'G', ref: 'G' }
];

export const INITIAL_OUT_PIPES: PipeData[] = [
  { id: 'X', ref: 'X' }, { id: 'Y', ref: 'Y' }
];

export const INITIAL_DATA: SurveyData = {
  cardNo: '', mapNo: '', catchment: '', mhNo: '', location: '', town: '',
  status: '', function: '', mhType: '', date: new Date().toISOString().split('T')[0], surveyor: '',
  coverShape: [], coverLevel: '', coverDuty: '', 
  coverLength: '', coverWidth: '', openingType: [], clearOpeningLength: '', clearOpeningWidth: '',
  incomingPipes: [...INITIAL_PIPES],
  outgoingPipes: [...INITIAL_OUT_PIPES],
  chamberSize: '', shaftSize: '', shaftDepth: '', constructionMaterial: [], ladderStepRows: '0',
  atmosphere: 'Clear', siltDebrisStatus: 'Minimal <10%',
  evidenceOfSurcharge: false, toxicAtmosphere: false,
  conditionCover: 'OK', conditionShaft: 'OK', conditionIrons: 'OK', conditionChamber: 'OK', conditionBenching: 'OK', conditionChannel: 'OK',
  depthFlow: '0', depthSilt: '0', surchargeHeight: '0',
  remarks: '',
  photo1Url: '', photo2Url: '', photo3Url: '', photo4Url: '',
};

import React, { useState } from 'react';
import { INITIAL_DATA, SurveyData, PipeData } from './types';
import { LOGO_URL, STATUS_OPTIONS, FUNCTION_OPTIONS, TYPE_OPTIONS, SHAPES, MATERIALS, OPENING_TYPES, ATMOSPHERE_OPTIONS, SILT_DEBRIS_OPTIONS } from './constants';
import PipeTable from './components/PipeTable';
import PhotoUpload from './components/PhotoUpload';
import { searchLocationInfo, fastAssist, enhanceRemarks } from './services/geminiService';

const App: React.FC = () => {
  const [data, setData] = useState<SurveyData>(INITIAL_DATA);
  const [loadingSearch, setLoadingSearch] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [assistantVisible, setAssistantVisible] = useState(false);
  const [assistantQuery, setAssistantQuery] = useState('');
  const [assistantResponse, setAssistantResponse] = useState('');

  const handleChange = (field: keyof SurveyData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const handlePipeChangeByRef = (ref: string, field: keyof PipeData, value: string) => {
    const isOutgoing = ['X', 'Y'].includes(ref);
    const listKey = isOutgoing ? 'outgoingPipes' : 'incomingPipes';
    const newList = [...data[listKey]];
    const index = newList.findIndex(p => p.ref === ref);
    if (index !== -1) {
      newList[index] = { ...newList[index], [field]: value };
      setData(prev => ({ ...prev, [listKey]: newList }));
    }
  };

  const toggleArrayItem = (field: keyof SurveyData, item: string) => {
    const current = (data[field] as string[]);
    const updated = current.includes(item) 
      ? current.filter(i => i !== item)
      : [...current, item];
    handleChange(field, updated);
  };

  const handleLocationSearch = async () => {
      if (!data.location) return;
      setLoadingSearch(true);
      const { text } = await searchLocationInfo(data.location);
      if (text) {
          setData(prev => ({
              ...prev,
              remarks: (prev.remarks + '\nVerified Location: ' + text).trim()
          }));
      }
      setLoadingSearch(false);
  };

  const handleEnhanceRemarks = async () => {
      if (!data.remarks) return;
      setEnhancing(true);
      const enhanced = await enhanceRemarks(data.remarks);
      handleChange('remarks', enhanced);
      setEnhancing(false);
  };

  const handleAssistantSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!assistantQuery) return;
      setAssistantResponse('Thinking...');
      const response = await fastAssist(assistantQuery);
      setAssistantResponse(response);
  };

  const handlePrint = () => {
    window.print();
  };

  const getConditionColorClass = (val: string) => {
    if (val === 'Needs Attention') return 'bg-yellow-100 print:bg-yellow-100';
    if (val === 'Urgent') return 'bg-orange-200 print:bg-orange-200';
    return '';
  };

  const getAtmosphereColor = (opt: string) => {
    switch (opt) {
      case 'Clear': return 'bg-green-100 text-green-800 border-green-300';
      case 'Toxic / O2 Deficiency': return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case 'Flammable Gas': return 'bg-orange-100 text-orange-800 border-orange-300';
      case 'DO NOT ENTER': return 'bg-red-600 text-white border-red-800';
      default: return 'bg-white border-slate-200';
    }
  };

  const getAtmosphereActiveColor = (opt: string) => {
    switch (opt) {
      case 'Clear': return 'bg-green-600 text-white border-green-700';
      case 'Toxic / O2 Deficiency': return 'bg-yellow-500 text-white border-yellow-600';
      case 'Flammable Gas': return 'bg-orange-600 text-white border-orange-700';
      case 'DO NOT ENTER': return 'bg-slate-900 text-white border-black';
      default: return 'bg-brand-600 text-white border-brand-700';
    }
  };

  const getSiltColor = (opt: string) => {
    switch (opt) {
      case 'Minimal <10%': return 'bg-green-100 text-green-800 border-green-300';
      case 'Moderate 10-25%': return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case 'Serious 25-50%': return 'bg-orange-100 text-orange-800 border-orange-300';
      case 'Severe >50%': return 'bg-red-100 text-red-800 border-red-300';
      case 'Blocked': return 'bg-slate-900 text-white border-black';
      default: return 'bg-white border-slate-200';
    }
  };

  const getSiltActiveColor = (opt: string) => {
    switch (opt) {
      case 'Minimal <10%': return 'bg-green-600 text-white border-green-700';
      case 'Moderate 10-25%': return 'bg-yellow-500 text-white border-yellow-600';
      case 'Serious 25-50%': return 'bg-orange-600 text-white border-orange-700';
      case 'Severe >50%': return 'bg-red-600 text-white border-red-700';
      case 'Blocked': return 'bg-slate-950 text-white border-black';
      default: return 'bg-brand-600 text-white border-brand-700';
    }
  };

  const allPipes = [...data.incomingPipes, ...data.outgoingPipes];

  return (
    <div className="min-h-screen bg-slate-100 p-4 md:p-8 font-sans print:p-0 print:bg-white">
      {/* Controls Bar (No Print) */}
      <div className="max-w-[210mm] mx-auto mb-6 flex justify-between items-center no-print">
        <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <span className="w-3 h-3 bg-brand-600 rounded-sm"></span>
            Smart Survey Portal
        </h1>
        <div className="flex gap-2">
            <button 
                onClick={() => setAssistantVisible(!assistantVisible)}
                className="bg-brand-600 text-white px-4 py-2 rounded shadow-md hover:bg-brand-700 transition flex items-center gap-2 text-sm"
            >
                🤖 Assistant
            </button>
            <button 
                onClick={handlePrint}
                className="bg-slate-800 text-white px-4 py-2 rounded shadow-md hover:bg-slate-900 transition flex items-center gap-2 text-sm"
            >
                🖨️ PDF Export
            </button>
        </div>
      </div>

      {/* Assistant Modal (No Print) */}
      {assistantVisible && (
          <div className="fixed right-4 bottom-4 w-80 bg-white rounded-lg shadow-2xl border border-slate-200 z-50 overflow-hidden no-print">
              <div className="bg-brand-600 p-3 text-white font-bold flex justify-between items-center">
                  <span>Smart Assistant</span>
                  <button onClick={() => setAssistantVisible(false)} className="hover:bg-brand-700 rounded px-1">✕</button>
              </div>
              <div className="p-4 h-64 overflow-y-auto bg-slate-50 text-xs">
                  {assistantResponse ? (
                      <div className="whitespace-pre-wrap">{assistantResponse}</div>
                  ) : (
                      <p className="text-slate-400 italic">Ask me about STC25 codes or help with technical observations...</p>
                  )}
              </div>
              <form onSubmit={handleAssistantSubmit} className="p-2 border-t flex gap-2 bg-white">
                  <input 
                    className="flex-1 border rounded px-3 py-1.5 text-xs focus:ring-1 focus:ring-brand-500 outline-none"
                    value={assistantQuery}
                    onChange={e => setAssistantQuery(e.target.value)}
                    placeholder="Type a question..."
                  />
                  <button type="submit" className="bg-brand-600 text-white px-3 py-1.5 rounded text-xs font-medium">Ask</button>
              </form>
          </div>
      )}

      {/* PAGE 1: FULL DATA SHEET */}
      <div className="page-segment">
        {/* Massive 400% Enlarged Faded Watermark */}
        <img src={LOGO_URL} alt="" className="watermark" />

        {/* Header Section - Logo 10% larger (h-10) */}
        <div className="flex justify-between items-start mb-4 border-b border-brand-900 pb-1 relative z-10">
            <div>
                <h1 className="text-lg font-bold text-slate-900 uppercase tracking-tight">Manhole Survey Card</h1>
                <p className="text-[9px] text-slate-500 font-mono">STC25 COMPLIANT REF: {data.mhNo || 'PENDING'}</p>
            </div>
            <div>
                <img src={LOGO_URL} alt="Clever Works" className="h-10 object-contain" />
            </div>
        </div>

        {/* Top Metadata Grid */}
        <div className="grid grid-cols-2 gap-x-4 gap-y-1.5 mb-3 text-[10px] relative z-10">
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Card No</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.cardNo} onChange={(e) => handleChange('cardNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Map No</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.mapNo} onChange={(e) => handleChange('mapNo', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-slate-600">Catchment</label>
                <input type="text" className="flex-1 border-b border-slate-300 px-1" value={data.catchment} onChange={(e) => handleChange('catchment', e.target.value)} />
            </div>
            <div className="flex items-center">
                <label className="w-20 font-bold text-brand-700">Manhole ID</label>
                <input type="text" className="flex-1 border-b border-brand-500 px-1 font-mono font-bold" value={data.mhNo} onChange={(e) => handleChange('mhNo', e.target.value)} />
            </div>
            <div className="col-span-2 flex items-center">
                <label className="w-20 font-bold text-slate-600">Location</label>
                <div className="flex-1 flex relative">
                     <input type="text" className="w-full border-b border-slate-300 px-1" value={data.location} onChange={(e) => handleChange('location', e.target.value)} />
                    <button onClick={handleLocationSearch} className="absolute right-0 top-0 text-brand-600 no-print text-[9px] hover:underline">GPS Verify</button>
