            <div className="flex justify-end">
                <button 
                    onClick={handleEnhanceRemarks}
                    disabled={enhancing || !data.remarks}
                    className="no-print bg-brand-600 hover:bg-brand-700 text-white text-[9px] font-bold py-1.5 px-4 rounded shadow-sm flex items-center gap-2 disabled:opacity-50 transition-all"
                >
                    {enhancing ? '✨ Professionalizing...' : '✨ AI Text Enhancer'}
                </button>
            </div>
        </div>
      </div>

      {/* PAGE 2: MEDIA & SKETCHES ONLY */}
      <div className="page-segment">
        {/* Massive 400% Enlarged Faded Watermark */}
        <img src={LOGO_URL} alt="" className="watermark" />

        {/* Header Section consistency - 10% bigger logo */}
