        <h3 className="text-[11px] font-bold uppercase mb-6 text-brand-900 border-b-4 border-brand-900 pb-2 relative z-10">Technical Sketch & Site Photos</h3>
        <div className="grid grid-cols-2 gap-8 relative z-10">
